#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        int *a = (int*)malloc(N*sizeof(int));
        int cnt[30]={0};
        for(int i=0;i<N;i++){
            scanf("%d",&a[i]);
            for(int b=0;b<30;b++) if(a[i]>>b & 1) cnt[b]++;
        }
        int essentialPos[N];
        for(int i=0;i<N;i++) essentialPos[i]=0;
        for(int b=0;b<30;b++) if(cnt[b]==1){
            for(int i=0;i<N;i++) if(a[i]>>b & 1){ essentialPos[i]=1; break; }
        }
        int maxLen=0, last=-1;
        for(int i=0;i<N;i++){
            if(essentialPos[i]){
                int len=i-last-1; if(len>maxLen) maxLen=len; last=i;
            }
        }
        int len=N-last-1; if(len>maxLen) maxLen=len;
        if(maxLen==0) printf("-1\n");
        else if(maxLen==N) printf("%d\n",N-1); // no essential, whole array not allowed
        else printf("%d\n",maxLen);
        free(a);
    }
    return 0;
}

