import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            int N = fs.nextInt();
            int[] a = new int[N];
            int[] cnt = new int[30];
            for (int i = 0; i < N; i++) {
                a[i] = fs.nextInt();
                for (int b = 0; b < 30; b++) if ((a[i] >> b & 1) == 1) cnt[b]++;
            }
            boolean[] essential = new boolean[N];
            for (int b = 0; b < 30; b++) if (cnt[b] == 1) {
                for (int i = 0; i < N; i++) if ((a[i] >> b & 1) == 1) { essential[i] = true; break; }
            }
            int maxLen = 0, last = -1;
            for (int i = 0; i < N; i++) {
                if (essential[i]) {
                    maxLen = Math.max(maxLen, i - last - 1);
                    last = i;
                }
            }
            maxLen = Math.max(maxLen, N - last - 1);
            if (maxLen == 0) sb.append(-1).append('\n');
            else if (maxLen == N) sb.append(N - 1).append('\n');
            else sb.append(maxLen).append('\n');
        }
        System.out.print(sb.toString());
    }
    // Fast scanner for large input
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in) { this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        int nextInt() throws IOException {
            int c, sign = 1, val = 0;
            do { c = readByte(); } while (c <= ' ');
            if (c == '-') { sign = -1; c = readByte(); }
            while (c > ' ') { val = val * 10 + (c - '0'); c = readByte(); }
            return val * sign;
        }
    }
}

