#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it))
        a = [int(next(it)) for _ in range(N)]
        cnt = [0]*30
        for val in a:
            for b in range(30):
                if val>>b & 1:
                    cnt[b] += 1
        essential = [False]*N
        for b in range(30):
            if cnt[b]==1:
                for i, val in enumerate(a):
                    if val>>b & 1:
                        essential[i] = True
                        break
        max_len = 0
        last = -1
        for i, e in enumerate(essential):
            if e:
                max_len = max(max_len, i-last-1)
                last = i
        max_len = max(max_len, N-last-1)
        if max_len == 0:
            out.append('-1')
        elif max_len == N:
            out.append(str(N-1))
        else:
            out.append(str(max_len))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

